/guides/lifecycle.exampleCode:
import { mount, onCreate, onRemove, unmount } from "valyrian.js";

const Clock = () => {
  onCreate(() => {
    const timer = setInterval(() => console.log(Date.now()), 1000);
    return () => clearInterval(timer);
  });
  onRemove(() => console.log("Clock removed"));
  return <time>Active</time>;
};

mount("body", Clock);
unmount();

/guides/update-control.exampleCode:
import { debouncedUpdate, mount, preventUpdate, update } from "valyrian.js";

let query = "";

const Search = () => (
  <main>
    <input
      value={query}
      oninput={(event: Event) => {
        query = (event.currentTarget as HTMLInputElement).value;
        preventUpdate();
        debouncedUpdate(150);
      }}
    />
    <button onclick={() => update()}>Refresh now</button>
  </main>
);

mount("body", Search);

